; 
; This question is based on the assumption that average property price is a key indicator of a neighborhood's property market; 
; Average income level helps in understanding the purchasing power and overall economic stability of a neighborhood.

sql:
SELECT mt.neighborhood_id, AVG(mt.average_price) AS average_market_price
FROM market_trends mt
GROUP BY mt.neighborhood_id;

SELECT neighborhood_id, year, average_price, number_of_transactions, average_days_on_market, median_days_on_market, median_price_per_square_foot
FROM market_trends
ORDER BY year DESC;

SELECT properties.property_id, properties.MEDV, market_trends.average_price
FROM properties
INNER JOIN market_trends ON properties.property_id = market_trends.property_id;

